@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    """
    Account recovery endpoint: accepts email and sends a reset link.
    The reset link will disable MFA, allowing the user to log in with just a password.
    No authentication required - this is for users locked out of their account.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Find user by email
    target_user = None
    for uid, user in users_db.items():
        if user['email'] == email:
            target_user = user
            break

    # Always return success to prevent email enumeration attacks
    success_message = (
        'If an account with that email exists and has MFA enabled, '
        'a reset link has been sent to the registered email address.'
    )

    if not target_user:
        return jsonify({'message': success_message}), 200

    if not target_user.get('mfa_enabled'):
        return jsonify({'message': success_message}), 200

    # Generate a secure, time-limited reset token
    token = secrets.token_urlsafe(48)
    expiry = datetime.utcnow() + timedelta(hours=1)

    mfa_reset_tokens[token] = {
        'user_id': target_user['user_id'],
        'email': email,
        'created_at': datetime.utcnow().isoformat(),
        'expires_at': expiry.isoformat(),
        'used': False
    }

    # Build reset link
    reset_link = url_for('confirm_reset_mfa', token=token, _external=True)

    # Send email with reset link
    email_subject = 'MFA Reset Request - Account Recovery'
    email_body = (
        f"Hello,\n\n"
        f"We received a request to reset the Multi-Factor Authentication (MFA) on your account.\n\n"
        f"Click the link below to disable MFA on your account. This link expires in 1 hour.\n\n"
        f"Reset Link: {reset_link}\n\n"
        f"If you did not request this reset, please ignore this email and ensure your account is secure.\n\n"
        f"For security, this link can only be used once.\n\n"
        f"- MFA Management System"
    )

    send_email(email, email_subject, email_body)

    return jsonify({'message': success_message}), 200


@app.route('/confirm-reset-mfa/<token>', methods=['GET', 'POST'])
def confirm_reset_mfa(token):
    """
    Endpoint that processes the MFA reset link.
    GET: Shows confirmation info.
    POST: Actually disables MFA for the user.
    """
    token_data = mfa_reset_tokens.get(token)

    if not token_data:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if token_data.get('used'):
        return jsonify({'error': 'This reset token has already been used'}), 400

    # Check expiry
    expiry = datetime.fromisoformat(token_data['expires_at'])
    if datetime.utcnow() > expiry:
        return jsonify({'error': 'This reset token has expired. Please request a new one.'}), 400

    user_id = token_data['user_id']
    user = users_db.get(user_id)

    if not user:
        return jsonify({'error': 'User account not found'}), 404

    if request.method == 'GET':
        return jsonify({
            'message': 'MFA reset token is valid. Send a POST request to this endpoint to confirm the reset.',
            'email': token_data['email'],
            'expires_at': token_data['expires_at']
        }), 200

    # POST: Disable MFA
    token_data['used'] = True
    token_data['used_at'] = datetime.utcnow().isoformat()

    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_verified_setup'] = False
    user['updated_at'] = datetime.utcnow().isoformat()

    # Send notification email about MFA being disabled
    notification_subject = 'MFA Has Been Disabled on Your Account'
    notification_body = (
        f"Hello,\n\n"
        f"Multi-Factor Authentication (MFA) has been disabled on your account "
        f"via the account recovery process.\n\n"
        f"You can now log in using just your email and password.\n\n"
        f"We strongly recommend re-enabling MFA after logging in to keep your account secure.\n\n"
        f"If you did not perform this action, please change your password immediately "
        f"and contact support.\n\n"
        f"- MFA Management System"
    )
    send_email(user['email'], notification_subject, notification_body)

    return jsonify({
        'message': 'MFA has been successfully disabled. You can now log in with your email and password.',
        'email': user['email']
    }), 200


